    private function handle_registration()
    {
        if (!isset($_POST['sua_register_nonce']) || !wp_verify_nonce($_POST['sua_register_nonce'], 'sua_register_action')) {
            $this->set_flash_message('Invalid registration request.', 'error');
            $this->safe_redirect();
        }

        $username = isset($_POST['username']) ? sanitize_user(wp_unslash($_POST['username'])) : '';
        $email = isset($_POST['email']) ? sanitize_email(wp_unslash($_POST['email'])) : '';
        $password = isset($_POST['password']) ? (string) wp_unslash($_POST['password']) : '';

        if (empty($username) || empty($email) || empty($password)) {
            $this->set_flash_message('All fields are required.', 'error');
            $this->safe_redirect();
        }

        if (username_exists($username)) {
            $this->set_flash_message('Username already exists.', 'error');
            $this->safe_redirect();
        }

        if (email_exists($email)) {
            $this->set_flash_message('Email already exists.', 'error');
            $this->safe_redirect();
        }

        if (!is_email($email)) {
            $this->set_flash_message('Invalid email address.', 'error');
            $this->safe_redirect();
        }

        if (strlen($password) < 6) {
            $this->set_flash_message('Password must be at least 6 characters long.', 'error');
            $this->safe_redirect();
        }

        $hashed_password = password_hash($password, PASSWORD_DEFAULT);

        if ($hashed_password === false) {
            $this->set_flash_message('Failed to securely hash password.', 'error');
            $this->safe_redirect();
        }

        $user_id = wp_insert_user([
            'user_login' => $username,
            'user_email' => $email,
            'user_pass'  => wp_generate_password(32, true, true),
            'role'       => 'subscriber',
        ]);

        if (is_wp_error($user_id)) {
            $this->set_flash_message($user_id->get_error_message(), 'error');
            $this->safe_redirect();
        }

        update_user_meta($user_id, 'sua_password_hash', $hashed_password);

        $this->set_flash_message('Registration successful. You can now log in.', 'success');
        $this->safe_redirect();
    }

    private function handle_login()
    {
        if (!isset($_POST['sua_login_nonce']) || !wp_verify_nonce($_POST['sua_login_nonce'], 'sua_login_action')) {
            $this->set_flash_message('Invalid login request.', 'error');
            $this->safe_redirect();
        }

        $identifier = isset($_POST['username']) ? sanitize_text_field(wp_unslash($_POST['username'])) : '';
        $password = isset($_POST['password']) ? (string) wp_unslash($_POST['password']) : '';

        if (empty($identifier) || empty($password)) {
            $this->set_flash_message('Both fields are required.', 'error');
            $this->safe_redirect();
        }

        $user = get_user_by('login', $identifier);

        if (!$user && is_email($identifier)) {
            $user = get_user_by('email', $identifier);
        }

        if (!$user) {
            $this->set_flash_message('Invalid credentials.', 'error');
            $this->safe_redirect();
        }

        $stored_hash = get_user_meta($user->ID, 'sua_password_hash', true);

        if (empty($stored_hash) || !password_verify($password, $stored_hash)) {
            $this->set_flash_message('Invalid credentials.', 'error');
            $this->safe_redirect();
        }

        if (password_needs_rehash($stored_hash, PASSWORD_DEFAULT)) {
            $new_hash = password_hash($password, PASSWORD_DEFAULT);
            if ($new_hash !== false) {
                update_user_meta($user->ID, 'sua_password_hash', $new_hash);
            }
        }

        wp_set_current_user($user->ID);
        wp_set_auth_cookie($user->ID, true);
        do_action('wp_login', $user->user_login, $user);

        $this->set_flash_message('Login successful.', 'success');
        $redirect = home_url();
        wp_safe_redirect($redirect);
        exit;
    }

    private function set_flash_message($message, $type = 'success')
    {
        if (!session_id()) {
            session_start();
        }

        $_SESSION['sua_flash_message'] = [
            'message' => $message,
            'type'    => $type,
        ];
