    private function get_flash_message()
    {
        if (!session_id()) {
            session_start();
        }

        if (empty($_SESSION['sua_flash_message'])) {
            return '';
        }

        $flash = $_SESSION['sua_flash_message'];
        unset($_SESSION['sua_flash_message']);

        $class = $flash['type'] === 'error' ? 'color:#b00020;' : 'color:#0a7d00;';
        return '<p style="' . esc_attr($class) . '">' . esc_html($flash['message']) . '</p>';
    }

